import base64
import json
import os

from google.cloud import firestore
from google.cloud import pubsub_v1
from google.cloud import storage

def process_gcs_file(event, context):
    """
    Google Cloud Function that processes a file from Cloud Storage,
    writes metadata to Firestore, and publishes a message to Pub/Sub.

    Args:
        event (dict): The Cloud Storage event payload.
        context (google.cloud.functions.Context): Metadata for the event.
    """

    file_name = event['name']
    bucket_name = event['bucket']
    content_type = event['contentType']
    time_created = event['timeCreated']
    size = event['size']
    resource_state = event['resourceState'] # 'EXISTS' or 'NOT_EXISTS' (for deletion)

    print(f"Processing file: {file_name} from bucket: {bucket_name}")
    print(f"Event ID: {context.event_id}")
    print(f"Event Type: {context.event_type}")

    if resource_state == 'NOT_EXISTS':
        print(f"File {file_name} was deleted. Skipping processing.")
        return

    # Initialize clients
    firestore_client = firestore.Client()
    pubsub_publisher = pubsub_v1.PublisherClient()
    storage_client = storage.Client()

    # --- 1. Read (or get metadata) from Cloud Storage ---
    try:
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        # You can download content here if needed, e.g., blob.download_as_text()
        # For this example, we're just using the event metadata.
        print(f"Successfully accessed GCS blob metadata for {file_name}.")
    except Exception as e:
        print(f"Error accessing GCS blob {file_name}: {e}")
        raise

    # --- 2. Write to Firestore ---
    firestore_collection_name = os.environ.get('FIRESTORE_COLLECTION', 'gcs_file_metadata')
    doc_ref = firestore_client.collection(firestore_collection_name).document(file_name.replace('/', '_')) # Use a sanitized file name as doc ID

    firestore_data = {
        'bucket': bucket_name,
        'file_name': file_name,
        'content_type': content_type,
        'size': int(size),
        'time_created': time_created,
        'processed_at': firestore.SERVER_TIMESTAMP,
        'event_id': context.event_id,
        'event_type': context.event_type
    }

    try:
        doc_ref.set(firestore_data)
        print(f"Successfully wrote metadata for {file_name} to Firestore document: {doc_ref.id}")
    except Exception as e:
        print(f"Error writing to Firestore for {file_name}: {e}")
        raise

    # --- 3. Publish to Pub/Sub ---
    pubsub_topic_name = os.environ.get('PUBSUB_TOPIC', 'gcs-file-events')
    project_id = os.environ.get('GCP_PROJECT') # Automatically set by Cloud Functions

    if not project_id:
        print("GCP_PROJECT environment variable not set. Cannot publish to Pub/Sub.")
        raise ValueError("GCP_PROJECT environment variable is required for Pub/Sub.")

    topic_path = pubsub_publisher.topic_path(project_id, pubsub_topic_name)

    pubsub_message_data = {
        'bucket': bucket_name,
        'file_name': file_name,
        'firestore_doc_id': doc_ref.id,
        'event_id': context.event_id
    }
    data_str = json.dumps(pubsub_message_data)
    data_bytes = data_str.encode('utf-8')

    try:
        future = pubsub_publisher.publish(topic_path, data_bytes)
        message_id = future.result()
        print(f"Published message for {file_name} to Pub/Sub topic {pubsub_topic_name} with ID: {message_id}")
    except Exception as e:
        print(f"Error publishing to Pub/Sub for {file_name}: {e}")
        raise

    print(f"Finished processing file: {file_name}")